deploy/oci/compute.tf.content:
locals {
  # Generate a random password for Oracle DB if not provided
  oracle_password = var.use_autonomous_db ? var.adb_admin_password : random_password.oracle_db.result
  oracle_mode     = var.use_autonomous_db ? "adb" : "freepdb"
  is_flex_shape   = length(regexall("Flex", var.instance_shape)) > 0
}

resource "random_password" "oracle_db" {
  length  = 16
  special = false
  upper   = true
  lower   = true
  numeric = true
}

resource "oci_core_instance" "picooraclaw" {
  compartment_id      = var.compartment_ocid
  availability_domain = data.oci_identity_availability_domains.ads.availability_domains[0].name
  display_name        = "picooraclaw"
  shape               = var.instance_shape

  dynamic "shape_config" {
    for_each = local.is_flex_shape ? [1] : []
    content {
      ocpus         = var.instance_ocpus
      memory_in_gbs = var.instance_memory_in_gbs
    }
  }

  source_details {
    source_type             = "image"
    source_id               = data.oci_core_images.ol9.images[0].id
    boot_volume_size_in_gbs = 100
  }

  create_vnic_details {
    subnet_id        = oci_core_subnet.picooraclaw.id
    assign_public_ip = true
    display_name     = "picooraclaw-vnic"
  }

  metadata = {
    ssh_authorized_keys = var.ssh_public_key
    user_data = base64encode(templatefile("${path.module}/cloud-init.yaml", {
      setup_script      = file("${path.module}/scripts/setup.sh")
      oracle_mode       = local.oracle_mode
      oracle_password   = local.oracle_password
      adb_dsn           = var.use_autonomous_db ? oci_database_autonomous_database.picooraclaw[0].connection_strings[0].all_connection_strings["LOW"] : ""
      adb_wallet_base64 = var.use_autonomous_db ? oci_database_autonomous_database_wallet.picooraclaw[0].content : ""
    }))
  }

  freeform_tags = {
    "app" = "picooraclaw"
  }
}

deploy/oci/main.tf.content:
provider "oci" {
  tenancy_ocid = var.tenancy_ocid
  region       = var.region
}

data "oci_identity_availability_domains" "ads" {
  compartment_id = var.tenancy_ocid
}

# Latest Oracle Linux 9 image for the chosen shape
data "oci_core_images" "ol9" {
  compartment_id           = var.compartment_ocid
  operating_system         = "Oracle Linux"
  operating_system_version = "9"
  shape                    = var.instance_shape
  sort_by                  = "TIMECREATED"
  sort_order               = "DESC"

  filter {
    name   = "launch_mode"
    values = ["NATIVE"]
  }
}

deploy/oci/network.tf.content:
resource "oci_core_vcn" "picooraclaw" {
  compartment_id = var.compartment_ocid
  display_name   = "picooraclaw-vcn"
  cidr_blocks    = [var.vcn_cidr]
  dns_label      = "picovcn"
}

resource "oci_core_internet_gateway" "picooraclaw" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.picooraclaw.id
  display_name   = "picooraclaw-igw"
  enabled        = true
}

resource "oci_core_route_table" "picooraclaw" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.picooraclaw.id
  display_name   = "picooraclaw-rt"

  route_rules {
    destination       = "0.0.0.0/0"
    network_entity_id = oci_core_internet_gateway.picooraclaw.id
  }
}

resource "oci_core_security_list" "picooraclaw" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.picooraclaw.id
  display_name   = "picooraclaw-sl"

  # Allow all egress
  egress_security_rules {
    destination = "0.0.0.0/0"
    protocol    = "all"
    stateless   = false
  }

  # SSH
  ingress_security_rules {
    source    = "0.0.0.0/0"
    protocol  = "6"
    stateless = false
    tcp_options {
      min = 22
      max = 22
    }
  }

  # Gateway API
  ingress_security_rules {
    source    = "0.0.0.0/0"
    protocol  = "6"
    stateless = false
    tcp_options {
      min = 18790
      max = 18790
    }
  }

  # ICMP
  ingress_security_rules {
    source    = "0.0.0.0/0"
    protocol  = "1"
    stateless = false
    icmp_options {
      type = 3
      code = 4
    }
  }
}

resource "oci_core_subnet" "picooraclaw" {
  compartment_id             = var.compartment_ocid
  vcn_id                     = oci_core_vcn.picooraclaw.id
  display_name               = "picooraclaw-subnet"
  cidr_block                 = cidrsubnet(var.vcn_cidr, 8, 1)
  dns_label                  = "picosub"
  route_table_id             = oci_core_route_table.picooraclaw.id
  security_list_ids          = [oci_core_security_list.picooraclaw.id]
  prohibit_public_ip_on_vnic = false
}

