func (o *OracleDBConfig) IsADB() bool {
	return o.Mode == "adb"
}

func (o *OracleDBConfig) UsesWallet() bool {
	return o.IsADB() && o.WalletPath != ""
}

func (o *OracleDBConfig) UsesTLS() bool {
	return o.IsADB() && o.DSN != "" && !o.UsesWallet()
}

