	mock.ExpectQuery("SELECT config_value FROM PICO_CONFIG").
		WithArgs("nonexistent", "test-agent").
		WillReturnRows(sqlmock.NewRows([]string{"config_value"}))

	val, err := store.GetConfigValue("nonexistent")
	if err != nil {
